    36→@Riverpod(keepAlive: true)
    37→class SubscriptionController extends _$SubscriptionController {
    38→  static final _logger = FimberLog('SubscriptionController');
    39→  static final Set<String> _processedIds = {};
    40→  StreamSubscription<List<PurchaseDetails>>? _purchaseStreamSubscription;
    41→
    42→  @override
    43→  Future<CurrentEntitlement?> build() async {
    44→    // 購入ストリームの購読と現在の権利情報の初期取得を行う
    45→    _startListeningToPurchaseStream();
    46→    updateCurrentEntitlement();
    47→    ref.onDispose(_dispose);
    48→    return null;
    49→  }
    50→
    51→  Future<void> _startListeningToPurchaseStream() async {
