    94→      // 有効な entitlement は最大で 1 つしか返ってこない
    95→      final entitlement = raw.first;
    96→      final map = Map<String, dynamic>.from(
    97→          (entitlement as Map).cast<String, dynamic>());
    98→      final currentEntitlement = CurrentEntitlement.fromJson(map);
    99→
   100→      state = AsyncValue.data(currentEntitlement);
   101→      _logger.i("Current Entitlement: $currentEntitlement");
   102→    } catch (e, _) {
   103→      _logger.e('Failed to fetch current entitlements', ex: e);
   104→    }
   105→  }
   106→
   107→  Future<bool> purchaseSubscription(ProductDetails productDetails) async {
   108→    try {
   109→      final teamId = ref.read(profileStorageProvider).getTeamId();
   110→      final param = PurchaseParam(
   111→        productDetails: productDetails,
   112→        applicationUserName: teamId,
   113→      );
   114→      // サブスクリプション商品の場合はbuyNonConsumableを使用
   115→      return await InAppPurchase.instance
   116→          .buyNonConsumable(purchaseParam: param);
   117→    } catch (e, stackTrace) {
   118→      if (e is PlatformException && e.code == 'storekit2_purchase_cancelled') {
   119→        rethrow;
   120→      }
   121→
   122→      _logger.e('Error initiating purchase', ex: e, stacktrace: stackTrace);
   123→      rethrow;
   124→    }
   125→  }
   126→
   127→  Future<void> handlePurchase(PurchaseDetails purchase) async {
   128→    _logger.i(
   129→      "handlePurchase : ${purchase.purchaseID} ${purchase.transactionDate} ${purchase.status}",
   130→    );
   131→
   132→    switch (purchase.status) {
   133→      case PurchaseStatus.pending:
   134→        // ここでは特に何もしない
   135→        return;
   136→      case PurchaseStatus.purchased:
   137→      case PurchaseStatus.restored:
   138→        // 購入完了時の処理。
   139→        // in_app_purchase_storekit 0.4.4 の既知の挙動:
   140→        // - 初回購入でも PurchaseStatus が restored になる場合がある
   141→        // - purchase.pendingCompletePurchase が常に false
   142→        // そのため常にサーバー検証を行い、成功時のみ completePurchase する。
   143→        // サーバー側は ASSN v2 経由で冪等に処理される前提。
   144→        try {
   145→          final decodedPayload = JwsDecoder.decodeTransactionPayload(
   146→            purchase.verificationData.serverVerificationData,
   147→          );
   148→
   149→          final teamId = ref.read(profileStorageProvider).getTeamId();
   150→
   151→          if (decodedPayload?.appAccountToken != teamId) {
   152→            // appAccountToken が一致しない: ユーザーが Team/User を切り替えた可能性。
   153→            // 自動更新分はサーバー側で検証するため、ここでは complete のみ行いストリームを捌く。
   154→            await InAppPurchase.instance.completePurchase(purchase);
   155→            _logger.i(
   156→              "App Account Token does not match. Expected: $teamId, Actual: ${decodedPayload?.appAccountToken}",
   157→            );
   158→            return;
   159→          }
   160→
   161→          if (decodedPayload?.transactionReason == 'RENEWAL') {
   162→            // 自動更新分はサーバー側で検証するため、ここでは complete のみ行いストリームを捌く。
   163→            await InAppPurchase.instance.completePurchase(purchase);
   164→            _logger.i("Auto renew subscription: $decodedPayload");
   165→            return;
   166→          }
   167→
   168→          final transactionId =
   169→              purchase.purchaseID ?? decodedPayload?.transactionId;
   170→          final webOrderLineItemId = decodedPayload?.webOrderLineItemId;
   171→
   172→          if (webOrderLineItemId == null || transactionId == null) {
   173→            // webOrderLineItemId が null の場合は処理をスキップ
   174→            _logger.e(
   175→                "webOrderLineItemId: $webOrderLineItemId transactionId $transactionId is null, cannot verify purchase");
   176→            return;
   177→          }
   178→
   179→          if (_processedIds.contains(webOrderLineItemId)) {
   180→            // 同一 webOrderLineItemId が同時に流れてきた場合の重複処理を防止
   181→            // in_app_purchase_storekit のバグで同一 ID でいくつもの purchase が流れてくることがある
   182→            await InAppPurchase.instance.completePurchase(purchase);
   183→            _logger.i(
   184→                "webOrderLineItemId $webOrderLineItemId is already being processed, skipping server validation");
   185→            return;
   186→          } else {
   187→            // 処理済みの webOrderLineItemId を Set に追加
   188→            _processedIds.add(webOrderLineItemId);
   189→          }
   190→
   191→          final result = await ref.read(repositoryProvider).verifyTransaction(
   192→                transactionId: transactionId,
   193→                webOrderLineItemId: webOrderLineItemId,
   194→              );
   195→
   196→          if (result.hasRight) {
   197→            // サーバー検証成功: complete 実行と entitlement の更新
   198→            await InAppPurchase.instance.completePurchase(purchase);
   199→            ref.read(purchaseFlowLoadingProvider.notifier).update(true);
   200→            await updateCurrentEntitlement();
   201→
   202→            _logger.i('Verify Transaction succeeded: $decodedPayload');
   203→
   204→            // アップグレード、自動更新ではサーバー側で Webhook を受け取って処理するため refresh するまでの
   205→            // 遅延を入れて反映させる
   206→            await Future.delayed(Duration(seconds: 8));
   207→            await ref
   208→                .read(teamListControllerProvider.notifier)
   209→                .refreshKeepingPrevious();
   210→            await updateCurrentEntitlement();
   211→          } else {
   212→            // 既に処理済みエラー: ストリームから取り除くため complete 実行
   213→            if (result.left is AlreadyProcessedAppleTransactionFailure) {
   214→              await InAppPurchase.instance.completePurchase(purchase);
   215→              await updateCurrentEntitlement();
   216→              _logger.i(
   217→                  "Error message ${result.left.message} returned. So completePurchase to remove this transaction from PurchaseStream. $decodedPayload");
   218→              return;
   219→            }
   220→
   221→            // サーバー検証失敗: complete せず、次回起動時に StoreKit が再送する想定。
   222→            _logger.e(
   223→              "Failed to create Apple Payment Session: ${result.left.message}. $decodedPayload",
   224→              ex: result.left,
   225→            );
   226→            // 再試行できるよう Set から除外
   227→            _processedIds.remove(webOrderLineItemId);
   228→          }
   229→        } catch (e, stackTrace) {
   230→          _logger.e(
   231→            'Error handling purchase for ${purchase.purchaseID}',
   232→            ex: e,
   233→            stacktrace: stackTrace,
   234→          );
   235→        } finally {
   236→          ref.read(purchaseFlowLoadingProvider.notifier).update(false);
   237→        }
   238→      case PurchaseStatus.error:
   239→        _logger.e("Purchase error: ${purchase.error}", ex: purchase.error);
   240→        return;
   241→      case PurchaseStatus.canceled:
   242→        return;
   243→    }
   244→  }
   245→}
   246→

