     1→// Package imports:
     2→import 'package:collection/collection.dart';
     3→import 'package:flutter_hooks/flutter_hooks.dart';
     4→import 'package:hooks_riverpod/hooks_riverpod.dart';
     5→
     6→// Project imports:
     7→import 'package:baseball_detector_flutter/controllers/subscription_controller.dart';
     8→import 'package:baseball_detector_flutter/controllers/team_list_controller.dart';
     9→import 'package:baseball_detector_flutter/data/result.dart';
    10→import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
    11→import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
    12→import 'package:baseball_detector_flutter/views/hooks/use_effect_once.dart';
    13→import 'package:baseball_detector_flutter/views/hooks/use_single_team_check.dart';
    14→import 'package:baseball_detector_flutter/views/hooks/use_widget_ref.dart';
    15→
    16→/// 現在のチームおよび現在のユーザー（Apple ID）に対する
    17→/// 有料プランの所有・利用可能状態を表します。
    18→enum SubscriptionStatus {
    19→  /// 現在のチームに対する有料プランを自分が所有している（Apple IAP）。
    20→  subscribedByMe,
    21→
    22→  /// プランの更新中。
    23→  updating,
    24→
    25→  /// 自分は有料プランを所有しているが、別のチームでの契約である。
    26→  subscribedByMeInOtherTeam,
    27→
    28→  /// チームは Web/Stripe で有料プランを契約中（Apple のトランザクションは存在しない）。
    29→  subscribedOnWeb,
    30→
    31→  /// 現在のチームでは別のメンバーが有料プランを所有している（Apple IAP）。
    32→  subscribedByTeammate,
    33→
    34→  /// 現在のチームにもユーザーにも有効な有料プランがない。
    35→  notSubscribed,
    36→  ;
    37→
    38→  /// 端末上で購入・アップグレードが可能かどうか
    39→  bool get canSubscribe => switch (this) {
    40→        SubscriptionStatus.notSubscribed ||
    41→        SubscriptionStatus.subscribedByMe =>
    42→          true,
    43→        _ => false,
    44→      };
    45→
    46→  /// プランの更新中かどうか
    47→  bool get isUpdating => this == updating;
    48→}
    49→
    50→SubscriptionStatus? useSubscriptionStatus() {
    51→  final ref = useWidgetRef();
    52→  final currentEntitlementState = ref.watch(subscriptionControllerProvider);
    53→  final teamList = ref.watch(teamListControllerProvider);
    54→  final teamId = ref.watch(profileStorageProvider).getTeamId();
    55→
    56→  // 初回マウント時に最新化のため invalidate する
    57→  useEffectOnce(() {
    58→    // ビルド直後に安全に実行するため microtask で包む
    59→    Future.microtask(() {
    60→      ref
    61→          .read(subscriptionControllerProvider.notifier)
    62→          .updateCurrentEntitlement();
    63→      ref.read(teamListControllerProvider.notifier).refreshKeepingPrevious();
    64→    });
    65→    return null;
    66→  });
    67→
    68→  final currentEntitlement = currentEntitlementState.when(
    69→    loading: () => null,
    70→    error: (_, __) => null,
    71→    data: (data) => data,
    72→  );
    73→
    74→  final (hasActivePaidPlan, team) = teamList.fold(
    75→      loading: () => (null, null),
    76→      error: (_) => (null, null),
    77→      data: (result) {
    78→        final team = result.firstWhereOrNull((team) => team.id == teamId);
    79→        // 現在有効なプランが存在する && そのプランが有料プランである
    80→        final hasActivePaidPlan = team?.teamPlan?.withinPeriod == true &&
