   102→    if (usage >= maxUsage) {
   103→      return TeamPlanStatus.reachedLimit;
   104→    }
   105→
   106→    // 4. 警告系（30日以内, 90%到達）
   107→    if (effectiveEndDate != null) {
   108→      final oneMonthLater = now.add(const Duration(days: 30));
   109→      if (effectiveEndDate.isAfter(now) &&
   110→          effectiveEndDate.isBefore(oneMonthLater)) {
   111→        return TeamPlanStatus.expiringSoon;
   112→      }
   113→    }
   114→    if (usage >= (maxUsage * 0.9).floor()) {
   115→      return TeamPlanStatus.limitIsApproaching;
   116→    }
