   105→        // 1
   106→        return SubscriptionStatus.subscribedByMe;
   107→      } else {
   108→        // 2
   109→        return SubscriptionStatus.updating;
   110→      }
   111→    } else {
   112→      // 3
   113→      return SubscriptionStatus.subscribedByMeInOtherTeam;
   114→    }
   115→  }
   116→
   117→  // CE なし
   118→  if (hasActivePaidPlan) {
   119→    return team?.teamPlan?.isStripeSubscription == true
   120→        // 4
   121→        ? SubscriptionStatus.subscribedOnWeb
   122→        // 5
   123→        : SubscriptionStatus.subscribedByTeammate;
   124→  }
   125→
   126→  // 6
   127→  return SubscriptionStatus.notSubscribed;
