import 'package:flutter/material.dart';

// Package imports:
import 'package:flutter_test/flutter_test.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/team_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/team_list_controller_fake.dart';
import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller.dart';
import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller_fake.dart';
import 'package:baseball_detector_flutter/data/models/plan.dart';
import 'package:baseball_detector_flutter/data/models/session.dart';
import 'package:baseball_detector_flutter/data/models/team.dart';
import 'package:baseball_detector_flutter/data/models/team_plan.dart';
import 'package:baseball_detector_flutter/data/profile_storage_fake.dart';
import 'package:baseball_detector_flutter/data/result.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/hooks/use_fab_state.dart';

void main() {
  group('useFabState', () {
    const testUserId = 'test-user-id';
    const testTeamId = 'test-team-id';
    final fixedNow = DateTime.utc(2024, 6, 1);
    late DateTime activePlanStartDate;
    late DateTime activePlanEndDate;
    final testSession = Session(
      id: 'session-1',
      userId: testUserId,
      teamId: testTeamId,
    );

    final mockProfileStorage = FakeProfileStorage(
      userId: testUserId,
      teamId: testTeamId,
    );

    setUp(() {
      overrideTeamPlanNow(() => fixedNow);
      activePlanStartDate = fixedNow.subtract(const Duration(days: 30));
      activePlanEndDate = fixedNow.add(const Duration(days: 365));
    });

    tearDown(resetTeamPlanNow);

    testWidgets('should return available when recording is available',
        (tester) async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 50,
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.available);
    });

    testWidgets(
        'should return needsSubscription when not premium and cannot analyze',
        (tester) async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 100, // reached limit
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.needsSubscription);
    });

    testWidgets('should return needsSubscription when plan expired',
        (tester) async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 10,
          isActive: true,
          startDate: fixedNow.subtract(const Duration(days: 400)),
          endDate: fixedNow.subtract(const Duration(days: 1)),
        ),
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.needsSubscription);
    });

    testWidgets('should return unavailable when premium plan and reached limit',
        (tester) async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'premium',
            maxBalls: 1000,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 1000, // reached limit
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.unavailable);
    });

    testWidgets(
        'should return available when premium plan but still has remaining balls',
        (tester) async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'premium',
            maxBalls: 1000,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 900, // approaching limit but not reached
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      // Premium だがボールが残っている場合は available になるべき
      expect(result, FabState.available);
    });

    testWidgets('should return unavailable when canSubscribe is false',
        (tester) async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 100, // reached limit
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: false, // cannot subscribe
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.unavailable);
    });

    testWidgets('should return unavailable when team not found',
        (tester) async {
      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider
                .overrideWith(() => FakeTeamListController(result: Right([]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.unavailable);
    });
  });
}

class _TestWidget extends HookConsumerWidget {
  const _TestWidget({
    required this.session,
    required this.teamId,
    required this.canSubscribe,
    required this.onResult,
  });

  final Session session;
  final String teamId;
  final bool canSubscribe;
  final void Function(FabState) onResult;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final state = useFabState(
      session: session,
      teamId: teamId,
      canSubscribe: canSubscribe,
    );

    onResult(state);

    return const SizedBox();
  }
}

